using System;
using System.ComponentModel;
using System.Drawing.Design;
using System.Runtime.InteropServices;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    private readonly StatusStrip _statusStrip;

    [Editor(typeof(DisplayNameEditor), typeof(UITypeEditor))]
    public string DisplayName { get; set; }

    public int MaxItems { get; set; }

    public MyControl()
    {
        _statusStrip = new StatusStrip
        {
            // .NET 9 breaking change: StatusStrip default RenderMode changed from
            // System to ManagerRenderMode. Set explicitly to preserve .NET 8 visuals.
            RenderMode = ToolStripRenderMode.System
        };
        _statusStrip.Items.Add(new ToolStripStatusLabel("Ready"));
        Controls.Add(_statusStrip);
    }

    public void UpdateStatus(string message)
    {
        if (_statusStrip.Items.Count > 0)
            _statusStrip.Items[0].Text = message;
    }
}

public class DisplayNameEditor : UITypeEditor
{
    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext context)
        => UITypeEditorEditStyle.DropDown;

    public override object EditValue(ITypeDescriptorContext context, IServiceProvider provider, object value)
    {
        if (provider?.GetService(typeof(IWindowsFormsEditorService)) is not IWindowsFormsEditorService editorService)
            return value;

        var control = CreateDropDownControl(value as string);

        // .NET 9 breaking change: DropDownControl now throws ArgumentNullException
        // when passed null. Always guard against null before calling.
        if (control is not null)
        {
            editorService.DropDownControl(control);
            value = (control as TextBox)?.Text ?? value;
        }

        return value;
    }

    private static Control CreateDropDownControl(string currentValue)
    {
        if (string.IsNullOrEmpty(currentValue))
            return null;

        return new TextBox { Text = currentValue };
    }
}

